phase1.code:
using UnityEngine;

public class Loops : MonoBehaviour
{
    void Start()
    {
        // for loop тАФ spawn 5 enemies
        Debug.Log("=== Spawning Enemies ===");
        for (int i = 0; i < 5; i++)
        {
            Debug.Log("Spawned enemy #" + (i + 1));
        }

        // while loop тАФ countdown
        Debug.Log("\n=== Countdown ===");
        int countdown = 5;
        while (countdown > 0)
        {
            Debug.Log(countdown + "...");
            countdown--;
        }
        Debug.Log("GO!");

        // foreach loop тАФ iterate over an array
        Debug.Log("\n=== Inventory ===");
        string[] items = { "Sword", "Shield", "Potion", "Key" };
        foreach (string item in items)
        {
            Debug.Log("Item: " + item);
        }

        // do-while тАФ runs at least once
        Debug.Log("\n=== Do-While ===");
        int attempts = 0;
        do
        {
            Debug.Log("Attempt " + (attempts + 1));
            attempts++;
        } while (attempts < 3);

        // break and continue
        Debug.Log("\n=== Break and Continue ===");
        for (int i = 0; i < 10; i++)
        {
            if (i == 3)
            {
                continue;  // Skip 3
            }
            if (i == 7)
            {
                break;     // Stop at 7
            }
            Debug.Log("Number: " + i);
        }
    }
}

phase1.explanation:
ЁЯОо **Loops repeat code multiple times.**

**`for` loop** тАФ when you know how many times to repeat:
```csharp
for (int i = 0; i < 5; i++)
{
    // Runs 5 times
}
```

**`while` loop** тАФ when you need to loop until a condition changes:
```csharp
while (health > 0)
{
    // Runs while health is above 0
}
```

**`foreach` loop** тАФ iterating over collections:
```csharp
foreach (string item in inventory)
{
    // Runs once per item
}
```

**`do-while` loop** тАФ always runs at least once:
```csharp
do
{
    // Runs at least once
} while (condition);
```

**Loop control:**
| Keyword | What it does |
|---------|--------------|
| `break` | Exits the loop immediately |
| `continue` | Skips the rest of this iteration |

